const express = require('express');
const app = express();

function sanitizeLogInput(input) {
  if (typeof input !== 'string') {
    return '';
  }
  // Remove newlines, carriage returns, tabs, and other control characters
  // This prevents log injection / log forging attacks
  return input
    .replace(/[\r\n\t]/g, '')
    .replace(/[\x00-\x1F\x7F]/g, '')
    .substring(0, 500); // Limit length to prevent log flooding
}

function isValidAction(action) {
  // Allow only alphanumeric characters, spaces, hyphens, underscores, and basic punctuation
  const allowedPattern = /^[a-zA-Z0-9 _\-.,;:!?()'"@#$%&+=]+$/;
  return allowedPattern.test(action);
}

app.get('/log-activity', (req, res) => {
  const rawAction = req.query.action;

  if (!rawAction) {
    return res.status(400).json({ error: 'Action parameter is required' });
  }

  const sanitizedAction = sanitizeLogInput(rawAction);

  if (sanitizedAction.length === 0) {
    return res.status(400).json({ error: 'Action parameter is empty after sanitization' });
  }

  if (!isValidAction(sanitizedAction)) {
    return res.status(400).json({ error: 'Action contains invalid characters' });
  }

  const timestamp = new Date().toISOString();
  const userIp = sanitizeLogInput(req.ip || 'unknown');

  // Use structured logging format to make log parsing reliable
  // and prevent injected content from being misinterpreted
  const logEntry = JSON.stringify({
    timestamp: timestamp,
    level: 'INFO',
    type: 'AUDIT',
    ip: userIp,
    action: sanitizedAction
  });

  console.log(logEntry);

  res.status(200).json({
    message: 'Activity logged successfully',
    timestamp: timestamp,
    action: sanitizedAction
  });
});

